import{_ as a,o as i,c as n,a3 as t}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"04. Pcns And Rpn 2. Advanced Application Process","description":"","frontmatter":{"title":"04. Pcns And Rpn 2. Advanced Application Process","eba":"Mental Health Services 2024-2028","topics":["schedules","classifications"]},"headers":[],"relativePath":"ebas/mental-health/schedules/04-pcns-and-rpn-2-advanced-application-process.md","filePath":"ebas/mental-health/schedules/04-pcns-and-rpn-2-advanced-application-process.md"}'),o={name:"ebas/mental-health/schedules/04-pcns-and-rpn-2-advanced-application-process.md"};function s(r,e,c,l,p,d){return i(),n("div",null,[...e[0]||(e[0]=[t('<h1 id="_04-pcns-and-rpn-2-advanced-application-process" tabindex="-1">04. Pcns And Rpn 2. Advanced Application Process <a class="header-anchor" href="#_04-pcns-and-rpn-2-advanced-application-process" aria-label="Permalink to &quot;04. Pcns And Rpn 2. Advanced Application Process&quot;">​</a></h1><p>Formatting note</p><p>The schedule body below is rendered in a monospaced block to preserve the column layout of pay tables and classification grids. The block is excluded from the search index so search results stay short; find schedules by their title, number, topic or synonyms.</p><p>```text SCHEDULE 4 : PCNS AND RPN 2 ADVANCED APPLICATION PROCESS 1. Application process to be classified to RPN 2 psychiatric clinical nurse specialist (PCNS) and RPN 2 advanced.</p><ol><li>For applications for the classification of RPN 2 PCNS or RPN 2 Advanced the following is to apply: (a) Each Employer will arrange, at regular times and not less than four occasions per year, for the calling of applications for classification to RPN 2 PCNS or RPN 2 1 Advanced. This information is to be permanently available to Psychiatric Nursing staff. All applications are to be considered on merit against the criteria. (b) Prospective applicants are encouraged to discuss RPN 2 PCNS or RPN 2 Advanced position with their Unit Manager prior to submitting an application. Written application is to be made to the Unit Manager. (c) Interviews may be conducted by a Psychiatric Nursing panel of no more than three and will include the Unit Manager, Associate Nurse Unit Manager or Psychiatric Nurse Consultant and one other. The decision to conduct formal interviews or not will be at the discretion of the Employer. However, no application will be refused solely on the basis that an interview was not conducted. (d) Some Employers (for example, where service delivery is similar across the facility) may wish to operate with an &#39;umbrella&#39; committee for the purpose of interviews. (e) The successful applicant will be notified in writing within seven days. The pay office will be informed of the new classification at the same time, which will apply from the FFPPOA the date of application. (f) If the applicant is unsuccessful, the applicant will be notified of the outcome within seven days and an explanation will be given as to the reasons for the decision and may, at the Employee&#39;s request, also include suggestions for a professional development plan. (g) Each Employer will implement an appeal process. The appeal is to be lodged by the applicant with the Unit Manager within two weeks of receiving the rejection letter and heard by the Appeal Committee within four weeks. (h) An independent appeal panel comprised of RPNs will be convened, from any of the following or their nominees: (i) The Mental Health Program Director howsoever titled (ii) The Senior Psychiatric Nurse (iii) Nurse Unit Manager (iv) An RPN 2 PCNS or RPN 2 Advanced or another nominee as appropriate. The appeal panel shall not include any person involved in the making of the original decision.</li></ol><p>SCHEDULE 4: PCNS AND RPN 2 ADVANCED APPLICATION PROCESS</p><p>SCHEDULE 4: PCNS AND RPN 2 ADVANCED APPLICATION PROCESS</p><ol><li><p>Any requirement to continue to meet the Psychiatric Clinical Nurse Specialist criteria (as set out in 108.9(c) to 108.9(e) will occur during rostered time.</p></li><li><p>Transfer of PCNS/RPN 2 Advanced Status where a person appointed as a PCNS/RPN2 Advanced by an Employer commences employment with another Employer within the same specialty, the new Employer will: (a) advise the PCNS/RPN2 Advanced of the next advertisement period referred to in SCHEDULE 42(a); and (b) where an application is made for the next advertisement period and is successful, the employee will be paid as a PCNS/RPN2 Advanced back to the date of commencement in the new role. Nothing in this sub-clause compels an Employee to make an application.</p></li></ol><p>SCHEDULE 4: PCNS AND RPN 2 ADVANCED APPLICATION PROCESS ```</p>',9)])])}const P=a(o,[["render",s]]);export{m as __pageData,P as default};
